import{_ as t,o as e,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Getting Started with Diamond Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),n={name:"getting-started/index.md"};function l(o,a,r,c,d,p){return e(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="getting-started-with-diamond-analytics" tabindex="-1">Getting Started with Diamond Analytics <a class="header-anchor" href="#getting-started-with-diamond-analytics" aria-label="Permalink to &quot;Getting Started with Diamond Analytics&quot;">​</a></h1><p>Diamond Analytics is a player development platform for youth baseball and softball coaches. It captures game and practice data, analyzes player performance, and connects observations to actionable training plans.</p><h2 id="what-diamond-analytics-does" tabindex="-1">What Diamond Analytics Does <a class="header-anchor" href="#what-diamond-analytics-does" aria-label="Permalink to &quot;What Diamond Analytics Does&quot;">​</a></h2><p><strong>During games and practices</strong> — coaches or parent volunteers log pitch locations, at-bat results, fielding plays, and baserunning events in real time. The app structures this raw data into analytics immediately.</p><p><strong>After games and practices</strong> — coaches review player and team analytics, identify development priorities, and create training plans. The suggestion engine automatically flags areas needing attention based on statistical thresholds.</p><p><strong>Throughout the season</strong> — player report cards track development over time and can be shared with families. Mechanics assessments document technique alongside statistics.</p><h2 id="quick-start-checklist" tabindex="-1">Quick Start Checklist <a class="header-anchor" href="#quick-start-checklist" aria-label="Permalink to &quot;Quick Start Checklist&quot;">​</a></h2><ol><li>Create your account at <a href="https://diamondanalytics.app" target="_blank" rel="noreferrer">diamondanalytics.app</a></li><li>Set up your first team — select Baseball or Softball</li><li>Add your roster</li><li>Choose your subscription plan (30-day free trial on Coach and Organization plans)</li><li>Install the app on your phone</li><li>Score your first game or practice</li></ol><h2 id="baseball-and-softball-support" tabindex="-1">Baseball and Softball Support <a class="header-anchor" href="#baseball-and-softball-support" aria-label="Permalink to &quot;Baseball and Softball Support&quot;">​</a></h2><p>Diamond Analytics fully supports both baseball and softball. When you create a team you select the sport and the app adjusts automatically:</p><ul><li><strong>Softball</strong> uses 60-foot base paths, a pitcher&#39;s circle at 43 feet, and softball pitch types (Rise Ball, Drop Ball, Curveball, Changeup, Screwball)</li><li><strong>Baseball</strong> uses standard 90-foot base paths and baseball pitch types</li><li>All analytics, mechanics assessments, and training plans work identically for both sports</li><li>A coach managing both baseball and softball teams uses a single subscription</li></ul>',11)])])}const m=t(n,[["render",l]]);export{u as __pageData,m as default};
